/**
 * Loan Audit PRO - src/report-template/reportTemplate.ts
 * ------------------------------------------------------------------
 * The professional client PDF report template (design variant B,
 * "Modern"), embedded as a base64 string with the BizBoost logo inlined
 * as a data-URI. The HTML is fully data-driven: real case data is
 * injected as window.REPORT_DATA before the template binds.
 * Presentation only - no financial figure is computed here.
 */
export const REPORT_TEMPLATE_B64 =
  "";

/** Decodes the embedded template to an HTML string. */
export function getReportTemplateHtml(): string {
  if (typeof atob === "function") {
    const bin = atob(REPORT_TEMPLATE_B64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i += 1) bytes[i] = bin.charCodeAt(i);
    return new TextDecoder("utf-8").decode(bytes);
  }
  return Buffer.from(REPORT_TEMPLATE_B64, "base64").toString("utf-8");
}
